**`frontend/src/api/authApi.ts`** (representative — others follow the same pattern)

```typescript
import axios from 'axios';
import type { User } from '@feastfite/shared';

const client = axios.create({
  baseURL: '/api/auth',
  headers: { 'Content-Type': 'application/json' },
});

interface AuthResponse {
  user: User;
  token: string;
}

export const authApi = {
  async login(email: string, password: string): Promise<AuthResponse> {
    const { data } = await client.post<AuthResponse>('/login', { email, password });
    return data;
  },

  async register(email: string, username: string, password: string): Promise<AuthResponse> {
    const { data } = await client.post<AuthResponse>('/register', {
      email,
      username,
      password,
    });
    return data;
  },

  async me(token: string): Promise<User> {
    const { data } = await client.get<User>('/me', {
      headers: { Authorization: `Bearer ${token}` },
    });
    return data;
  },
};
```

The other API clients follow the same pattern with their own `baseURL`:
- `territoryApi.ts`: `baseURL: '/api/territory'`
- `voteApi.ts`: `baseURL: '/api/vote'`
- `economyApi.ts`: `baseURL: '/api/economy'`
- `profileApi.ts`: `baseURL: '/api/profile'`

