**File 8: `packages/shared/src/utils/jwt.ts`**

```typescript
import jwt, { type JwtPayload, type SignOptions } from 'jsonwebtoken';

export interface FeastFiteJwtPayload extends JwtPayload {
  userId: string;
  email: string;
  username: string;
}

export function verifyToken(token: string, secret?: string): FeastFiteJwtPayload {
  const jwtSecret = secret ?? process.env['JWT_SECRET'];
  if (!jwtSecret) {
    throw new Error('JWT_SECRET is not configured');
  }
  const payload = jwt.verify(token, jwtSecret);
  if (typeof payload === 'string') {
    throw new Error('Unexpected string JWT payload');
  }
  return payload as FeastFiteJwtPayload;
}

export function signToken(
  payload: Omit<FeastFiteJwtPayload, keyof JwtPayload>,
  secret?: string,
  options?: SignOptions
): string {
  const jwtSecret = secret ?? process.env['JWT_SECRET'];
  if (!jwtSecret) {
    throw new Error('JWT_SECRET is not configured');
  }
  return jwt.sign(payload, jwtSecret, {
    expiresIn: process.env['JWT_EXPIRES_IN'] ?? '15m',
    ...options,
  });
}
```

Note: `signToken` is included here alongside `verifyToken` because auth-service will need it, and the API gateway Kong plugin validates tokens — there is no reason to sign tokens anywhere except auth-service. By putting both in shared, auth-service can import `signToken` while every other service only imports `verifyToken`.

